namespace batt {

namespace detail {

class AttachCount
{
   public:
    void inc(i64 delta)
    {
        BATT_CHECK_GE(delta, 0);
        this->counter_.fetch_add(delta);
    }

    void dec(i64 delta)
    {
        BATT_CHECK_GE(delta, 0);
        this->counter_.fetch_sub(delta);
    }

    bool wait_for_inactive() noexcept
    {
        bool waited = false;
        while (this->counter_.load() > 0) {
            Task::yield();
            waited = true;
        }
        return waited;
    }

   private:
    std::atomic<i64> counter_{0};
};

}  // namespace detail

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T>
class ObjectThreadStorage
{
   public:
    using Self = ObjectThreadStorage;

    // Forward-declarations.
    //
    class SlotState;
    class ThreadState;
    class SlotThreadData;
    class ScopedSlot;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    class SlotThreadData
    {
       public:
        using Self = SlotThreadData;

        //----- --- -- -  -  -   -

        explicit SlotThreadData(ThreadState* thread_state) noexcept : thread_state_{thread_state}
        {
        }

        SlotThreadData(const Self&) = delete;

        Self& operator=(const Self&) = delete;

        //----- --- -- -  -  -   -

        ThreadState* get_thread_state() const noexcept
        {
            return this->thread_state_;
        }

        template <typename... Args>
        T& construct(Args&&... args)
        {
            return *(new (&this->storage_) T(BATT_FORWARD(args)...));
        }

        void attach_slot(SlotState* slot) noexcept
        {
            BATT_CHECK_EQ(this->slot_.exchange(slot), nullptr);
        }

        SlotState* detach_slot() noexcept
        {
            return this->slot_.exchange(nullptr);
        }

        void destruct() noexcept
        {
            BATT_CHECK_EQ(this->slot_.load(), nullptr);
            this->get().~T();
        }

        //----- --- -- -  -  -   -

        BATT_ALWAYS_INLINE bool is_valid() const noexcept
        {
            return this->slot_.load() != nullptr;
        }

        BATT_ALWAYS_INLINE T& get() noexcept
        {
            return *reinterpret_cast<T*>(&this->storage_);
        }

        //----- --- -- -  -  -   -
       private:
        // The memory where the T instance is constructed. MUST BE FIRST
        //
        std::aligned_storage_t<sizeof(T), alignof(T)> storage_;

        // The slot (if any) to which this object is 'attached.'  If this is non-null, then this->storage_
        // contains a valid instance of T.
        //
        std::atomic<SlotState*> slot_{nullptr};

        // Pointer back to the thread that created/owns this object.
        //
        ThreadState* const thread_state_{nullptr};

        //----- --- -- -  -  -   -
       public:
        // Used to add this object to SlotState-specific linked lists. MUST BE PUBLIC
        //
        boost::intrusive::list_member_hook<> list_hook_;
    };

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    static constexpr usize kInvalidSlot = ~usize{0} >> 24;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    static Self& instance()
    {
        // Intentionally leak `instance_` to avoid dtor ordering problems on shutdown.
        //
        static Self* instance_ = new Self{};

        return *instance_;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    ObjectThreadStorage() = default;

    usize allocate_slot()
    {
        usize slot_i = kInvalidSlot;

        if (this->slot_index_pool_.pop(slot_i)) {
            BATT_CHECK_NE(slot_i, kInvalidSlot);
            return slot_i;
        }
        return this->next_unused_slot_index_.fetch_add(1);
    }

    void deallocate_slot(usize slot_i)
    {
        this->slot_index_pool_.push(slot_i);
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    // The pool of deallocated slot indices which are available for re-allocation.
    //
    boost::lockfree::stack<usize> slot_index_pool_{/*initial_nodes=*/16};

    // If we need to allocate a slot index and the pool is empty, this counter is incremented.
    //
    std::atomic<usize> next_unused_slot_index_{0};
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T>
class ObjectThreadStorage<T>::ThreadState
{
   public:
    using Self = ThreadState;

    static Self& instance() noexcept
    {
        thread_local Self instance_;
        return instance_;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    ThreadState() noexcept
    {
    }

    ThreadState(const ThreadState&) = delete;
    ThreadState& operator=(const ThreadState&) = delete;

    ~ThreadState() noexcept
    {
        // Try to detach all active SlotThreadData objects from their SlotState, running the destructors of
        // the ones for which we 'win' the race to do so.
        //
        for (auto& ptr : this->slots_) {
            if (!ptr) {
                continue;
            }

            // Atomically exchange the slot pointer with null; if the prior value is non-null, then the object
            // *is* in use and we managed to do this before the associated SlotState did the same.  In this
            // case, we are on the hook to run the object's destructor and then decrease the attach counts for
            // ThreadState (this) and SlotState.
            //
            SlotState* slot = ptr->detach_slot();
            if (slot != nullptr) {
                // Note: there is *no* race between these operations and the prior construct and SlotState
                // attach operations, because by definition they happened on this thread.
                //
                slot->detach_thread_data(*ptr);
                ptr->destruct();

                // It does not matter which order we run these two decrements, but they both *must* come after
                // detaching from the SlotState's list and calling ~T().
                //
                slot->attach_count().dec(1);
                this->attach_count().dec(1);
            }
        }

        // Wait for any SlotStates to whom we lost the race to claim a SlotThreadData object.
        //
        [[maybe_unused]] const bool waited = this->attach_count().wait_for_inactive();
    }

    detail::AttachCount& attach_count() noexcept
    {
        return this->attach_count_;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    BATT_ALWAYS_INLINE SlotThreadData& get_slot(usize slot_i)
    {
        if (BATT_HINT_FALSE(this->slots_.size() <= slot_i)) {
            this->slots_.resize(slot_i + 1);
        }

        std::unique_ptr<SlotThreadData>& ptr = this->slots_[slot_i];

        if (ptr == nullptr) {
            ptr = std::make_unique<SlotThreadData>(this);
        }

        return *ptr;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    detail::AttachCount attach_count_;
    std::vector<std::unique_ptr<SlotThreadData>> slots_;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T>
class ObjectThreadStorage<T>::SlotState
{
   public:
    static constexpr usize kInvalidSlot = ObjectThreadStorage<T>::kInvalidSlot;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    SlotState() noexcept = default;

    ~SlotState() noexcept
    {
        {
            ThreadDataList tmp_list;

            // Transfer to `tmp_list` all data objects for we can claim exclusive rights to detach.
            //
            {
                std::unique_lock<std::mutex> lock{this->mutex_};

                // Try to claim all elements of the list by calling `detach_slot()`; note, we are racing
                // with each of the individual ThreadState objects, which may be scoped to threads in the
                // process of exiting.  This is why we only retain the objects successfully 'claimed' via
                // `detach_slot()`.
                //
                auto next = this->thread_data_list_.begin();
                const auto last = this->thread_data_list_.end();
                while (next != last) {
                    SlotThreadData& data = *next;
                    SlotState* const prev_slot = data.detach_slot();
                    if (prev_slot != nullptr) {
                        // Success!  Sanity check and continue.
                        //
                        // (We will run destructors and decrease attach counts below, once the mutex is
                        // released).
                        //
                        BATT_CHECK_EQ(prev_slot, this);

                        next = this->thread_data_list_.erase(next);
                        tmp_list.push_back(data);

                    } else {
                        // Lost the race; on to the next one...
                        //
                        ++next;
                    }
                }

            }  // Release the mutex.

            // Run destructors without locks held.  Note, we have to iterate through the list in this awkward
            // way of popping the first one until it is empty, because as soon as we decrease the thread state
            // attach counter, the SlotThreadData object may be immediately deleted, taking its list node
            // pointers with it.
            //
            while (!tmp_list.empty()) {
                // Remove the node from the list *before* calling destruct and decrementing the attach counts.
                //
                SlotThreadData& data = tmp_list.front();
                tmp_list.pop_front();

                // Run type-specific destructor (~T()).
                //
                data.destruct();

                // Now the attach counts can be decremented.
                //
                this->attach_count().dec(1);
                data.get_thread_state()->attach_count().dec(1);
            }
        }

        // Here we wait for any threads to whom we lost the race (above) to detach a SlotThreadData object.
        // This is how we guarantee that by the time ~SlotState() returns, all destructors for thread-local
        // objects have run.
        //
        // Note, because ThreadState has no way of knowing that SlotState is destructing, we must allow
        // ThreadState to remove each remaining list node via SlotState::detach_thread_data.
        //
        [[maybe_unused]] const bool waited = this->attach_count_.wait_for_inactive();

        // Now we can assert that the list is empty.
        //
        {
            std::unique_lock<std::mutex> lock{this->mutex_};
            BATT_CHECK(this->thread_data_list_.empty());
        }
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    SlotState(const SlotState&) = delete;

    SlotState& operator=(const SlotState&) = delete;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    detail::AttachCount& attach_count() noexcept
    {
        return this->attach_count_;
    }

    template <typename Fn>
#if BATT_CPP_20
        requires std::invocable<Fn, T&> && std::convertible_to<std::invoke_result_t<Fn, T&>, bool>
#endif
    bool visit_each(Fn&& fn)
    {
        std::unique_lock<std::mutex> lock{this->mutex_};

        for (SlotThreadData& thread_data : this->thread_data_list_) {
            if (fn(thread_data.get())) {
                return true;
            }
        }

        return false;
    }

    void attach_thread_data(SlotThreadData& data)
    {
        std::unique_lock<std::mutex> lock{this->mutex_};
        this->thread_data_list_.push_front(data);
    }

    void detach_thread_data(SlotThreadData& data)
    {
        std::unique_lock<std::mutex> lock{this->mutex_};
        this->thread_data_list_.erase(this->thread_data_list_.iterator_to(data));
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    using ThreadDataList = boost::intrusive::list<                           //
        SlotThreadData,                                                      //
        boost::intrusive::member_hook<SlotThreadData,                        //
                                      boost::intrusive::list_member_hook<>,  //
                                      &SlotThreadData::list_hook_>>;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    // Tracks number of active attached slot data objects.
    //
    detail::AttachCount attach_count_;

    // Slot-scoped mutex.
    //
    std::mutex mutex_;

    // Double-linked list of slot thread data objects.
    //
    ThreadDataList thread_data_list_;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T>
class ObjectThreadStorage<T>::ScopedSlot
{
   public:
    static constexpr usize kInvalidSlot = ObjectThreadStorage<T>::kInvalidSlot;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    ScopedSlot() noexcept : slot_i_{ObjectThreadStorage<T>::instance().allocate_slot()}
    {
    }

    ~ScopedSlot() noexcept
    {
        if (this->is_valid()) {
            this->state_.reset();
            ObjectThreadStorage<T>::instance().deallocate_slot(this->slot_i_);
        }
    }

    ScopedSlot(const ScopedSlot&) = delete;
    ScopedSlot& operator=(const ScopedSlot&) = delete;

    ScopedSlot(ScopedSlot&& other) noexcept
        : slot_i_{std::exchange(other.slot_i_, kInvalidSlot)}
        , state_{std::move(other.state_)}
    {
    }

    ScopedSlot& operator=(ScopedSlot&& other) noexcept
    {
        if (this != &other) {
            this->slot_i_ = std::exchange(other.slot_i_, kInvalidSlot);
            this->state_ = std::move(other.state_);
        }
        return *this;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    bool is_valid() const noexcept
    {
        return this->state_ != nullptr;
    }

    usize index() const noexcept
    {
        return this->slot_i_;
    }

    template <typename... Args>
    T& get(Args&&... args)
    {
        ThreadState& thread_state = ObjectThreadStorage<T>::ThreadState::instance();
        SlotThreadData& data = thread_state.get_slot(this->slot_i_);

        if (BATT_HINT_FALSE(!data.is_valid())) {
            // First, increment the attachment count for both the slot and the thread, to prevent dangling
            // references.
            //
            thread_state.attach_count().inc(1);
            this->state_->attach_count().inc(1);

            // Initialize this thread/slot's instance of T.
            //
            data.construct(BATT_FORWARD(args)...);

            // Link the SlotThreadData object to this.
            //
            data.attach_slot(this->state_.get());
            this->state_->attach_thread_data(data);
        }

        return data.get();
    }

    template <typename Fn>
#if BATT_CPP_20
        requires std::invocable<Fn, T&> && std::convertible_to<std::invoke_result_t<Fn, T&>, bool>
#endif
    bool visit_each(Fn&& fn)
    {
        return this->state_->visit_each(BATT_FORWARD(fn));
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    // The slot index.
    //
    usize slot_i_;

    std::unique_ptr<SlotState> state_ = std::make_unique<SlotState>();
};

}  // namespace batt
